    /** pdoc search index */const docs = [{"fullname": "ssscoring", "modulename": "ssscoring", "kind": "module", "doc": "<p>Speed Skydiving Scoring tools package for processing FlySight v1 and v2 CSV data\nfiles.</p>\n\n<p>This library relies on NumPy and pandas.  When running in a Lucyfer notebook or\nin Streamlit.io, it also requires the Bokeh plotting library.</p>\n\n<h2 id=\"installation\">Installation</h2>\n\n<div class=\"pdoc-code codehilite\">\n<pre><span></span><code>pip<span class=\"w\"> </span>install<span class=\"w\"> </span>-U<span class=\"w\"> </span>ssscoring\n</code></pre>\n</div>\n\n<h2 id=\"source-code\">Source code</h2>\n\n<p>You are welcome to <strong><a href='https://github.com/pr3d4t0r/SSScoring' target='_new'>fork SSScoring</a></strong>\non GitHub.  You will need Python 3.9 or later, pandas, and NumPy as minimum\nrequirements.</p>\n\n<p>You may study or download the latest stable source files at:</p>\n\n<p><a href='https://github.com/pr3d4t0r/SSScoring/tree/master/ssscoring' target='_new'><a href=\"https://github.com/pr3d4t0r/SSScoring/tree/master/ssscoring\">https://github.com/pr3d4t0r/SSScoring/tree/master/ssscoring</a></a></p>\n"}, {"fullname": "ssscoring.__VERSION__", "modulename": "ssscoring", "qualname": "__VERSION__", "kind": "variable", "doc": "<p>@public</p>\n", "default_value": "&#x27;2.10.4&#x27;"}, {"fullname": "ssscoring.appcommon", "modulename": "ssscoring.appcommon", "kind": "module", "doc": "<p>Common functions, classes, and objects to all Streamlit apps in the SSScoring\npackage.</p>\n"}, {"fullname": "ssscoring.appcommon.DEFAULT_DATA_LAKE", "modulename": "ssscoring.appcommon", "qualname": "DEFAULT_DATA_LAKE", "kind": "variable", "doc": "<p>Default data lake directory when reading files from the local file system.</p>\n", "default_value": "&#x27;./data&#x27;"}, {"fullname": "ssscoring.appcommon.STREAMLIT_SIG_KEY", "modulename": "ssscoring.appcommon", "qualname": "STREAMLIT_SIG_KEY", "kind": "variable", "doc": "<p>Environment key used by the Streamlig.app environment when running an\napplication.</p>\n", "default_value": "&#x27;HOSTNAME&#x27;"}, {"fullname": "ssscoring.appcommon.STREAMLIT_SIG_VALUE", "modulename": "ssscoring.appcommon", "qualname": "STREAMLIT_SIG_VALUE", "kind": "variable", "doc": "<p>Expected value associate with the environment variable <code>STREAMLIT_SIG_KEY</code> when\nrunning in a Streamlit.app environment.</p>\n", "default_value": "&#x27;streamlit&#x27;"}, {"fullname": "ssscoring.appcommon.isStreamlitHostedApp", "modulename": "ssscoring.appcommon", "qualname": "isStreamlitHostedApp", "kind": "function", "doc": "<p>Detect if the hosting environment is a native Python system or a Streamlit\napp environment hosted by streamlit.io or Snowflake.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p><code>True</code> if the app is running in the Streamlit app or Snoflake app\nenvironment, otherwise <code>False</code>.</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"return-annotation\">) -> <span class=\"nb\">bool</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.appcommon.fetchResource", "modulename": "ssscoring.appcommon", "qualname": "fetchResource", "kind": "function", "doc": "<p>Fetch a file-like resource from the <code>PYTHONPATH</code> and <code>resources</code> module\nincluded in the SSScore package.  Common resources include the drop zones\nlist CSV and in-line documentation Markdown text.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>resourceName\n</code></pre>\n\n<p>A string representing the resource file name, usually a CSV file.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p>An instance of <code>StringIO</code> ready to be process as a text stream by the\ncaller.</p>\n\n<h2 id=\"raises\">Raises</h2>\n\n<p><code>SSScoringError</code> if the resource dataframe isn't the global drop zones\ndirectory or the file is invalid in any way.</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">resourceName</span><span class=\"p\">:</span> <span class=\"nb\">str</span></span><span class=\"return-annotation\">) -> <span class=\"n\">_io</span><span class=\"o\">.</span><span class=\"n\">StringIO</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.appcommon.initDropZonesFromResource", "modulename": "ssscoring.appcommon", "qualname": "initDropZonesFromResource", "kind": "function", "doc": "<p>Get the DZs directory from a CSV enclosed in the distribution package as a\nresource.  The resources package is fixed to <code>ssscoring.resources</code>, the\ndefault resource file is defined by <code>DZ_DIRECTORY</code> but can be anything.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p>The global drop zones directory as a dataframe.</p>\n\n<h2 id=\"raises\">Raises</h2>\n\n<p><code>SSScoringError</code> if the resource dataframe isn't the global drop zones\ndirectory or the file is invalid in any way.</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"return-annotation\">) -> <span class=\"n\">pandas</span><span class=\"o\">.</span><span class=\"n\">core</span><span class=\"o\">.</span><span class=\"n\">frame</span><span class=\"o\">.</span><span class=\"n\">DataFrame</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.appcommon.displayJumpDataIn", "modulename": "ssscoring.appcommon", "qualname": "displayJumpDataIn", "kind": "function", "doc": "<p>Display the individual results, as a table.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>resultsTable: pd.DataFrame\n</code></pre>\n\n<p>The results from a speed skydiving jump.</p>\n\n<h2 id=\"see\">See</h2>\n\n<p><code>ssscoring.datatypes.JumpResults</code></p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">resultsTable</span><span class=\"p\">:</span> <span class=\"n\">pandas</span><span class=\"o\">.</span><span class=\"n\">core</span><span class=\"o\">.</span><span class=\"n\">frame</span><span class=\"o\">.</span><span class=\"n\">DataFrame</span></span><span class=\"return-annotation\">):</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.appcommon.interpretJumpResult", "modulename": "ssscoring.appcommon", "qualname": "interpretJumpResult", "kind": "function", "doc": "<p>Interpret the jump results and generate the corresponding labels and\nwarnings if a jump is invalid, or only \"somewhat valid\" according to ISC\nrules.  The caller turns results display on/off depending on training vs\nin-competition settins.  Because heuristics are a beautiful thing.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>tag\n</code></pre>\n\n<p>A string that identifies a specific jump and the FlySight version that\ngenerated the corresponding track file.  Often in the form: <code>HH-mm-ss:vX</code>\nwhere <code>X</code> is the FlySight hardware version.</p>\n\n<pre><code>jumpResult\n</code></pre>\n\n<p>An instance of <code>ssscoring.datatypes.JumpResults</code> with jump data.</p>\n\n<pre><code>processBadJump\n</code></pre>\n\n<p>If <code>True</code>, generate end-user warnings as part of its results processing if\nthe jump is invalid because of ISC rules, but set the status to OK so that\nthe jump may be displayed.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p>A <code>tuple</code> of these objects:</p>\n\n<ul>\n<li><code>jumpStatusInfo</code> - the jump status, in human-readable form</li>\n<li><code>scoringInfo</code> - Max speed, scoring window, etc.</li>\n<li><code>badJumpLegend</code> - A warning or error if the jump is invalid according to\nISC rules</li>\n<li><code>jumpStatus</code> - An instance of <code>JumpStatus</code> that may have been overriden to\n<code>OK</code> if <code>processBadJump</code> was set to <code>True</code> and the jump was invalid.  Used\nonly for display.  Use <code>jumpResult.status</code> to determine the actual result\nof the jump from a strict scoring perspective.  <code>jumpStatus</code> is  used\nfor display override purposes only.</li>\n</ul>\n", "signature": "<span class=\"signature pdoc-code multiline\">(<span class=\"param\">\t<span class=\"n\">tag</span><span class=\"p\">:</span> <span class=\"nb\">str</span>,</span><span class=\"param\">\t<span class=\"n\">jumpResult</span><span class=\"p\">:</span> <span class=\"n\">ssscoring</span><span class=\"o\">.</span><span class=\"n\">datatypes</span><span class=\"o\">.</span><span class=\"n\">JumpResults</span>,</span><span class=\"param\">\t<span class=\"n\">processBadJump</span><span class=\"p\">:</span> <span class=\"nb\">bool</span></span><span class=\"return-annotation\">):</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.appcommon.plotJumpResult", "modulename": "ssscoring.appcommon", "qualname": "plotJumpResult", "kind": "function", "doc": "<p>Plot the jump results including altitude, horizontal speed, time, etc. for\nevaluation and interpretation.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>tag\n</code></pre>\n\n<p>A string that identifies a specific jump and the FlySight version that\ngenerated the corresponding track file.  Often in the form: <code>HH-mm-ss:vX</code>\nwhere <code>X</code> is the FlySight hardware version.</p>\n\n<pre><code>jumpResult\n</code></pre>\n\n<p>An instance of <code>ssscoring.datatypes.JumpResults</code> with jump data.</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">tag</span><span class=\"p\">:</span> <span class=\"nb\">str</span>, </span><span class=\"param\"><span class=\"n\">jumpResult</span><span class=\"p\">:</span> <span class=\"n\">ssscoring</span><span class=\"o\">.</span><span class=\"n\">datatypes</span><span class=\"o\">.</span><span class=\"n\">JumpResults</span></span><span class=\"return-annotation\">):</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.appcommon.initFileUploaderState", "modulename": "ssscoring.appcommon", "qualname": "initFileUploaderState", "kind": "function", "doc": "<p>Initialize the session state for the Streamlit app uploader so that\nselections can be cleared in callbacks later.</p>\n\n<p><strong>Important</strong>: <code>initFileUploaderState()</code> __must__ be called after setting the\npage configuration (per Streamlit architecture rules) and before adding any\nwidgets to the sidebars, containers, or main application.</p>\n\n<h2 id=\"argument\">Argument</h2>\n\n<pre><code>filesObject\n</code></pre>\n\n<p>A <code>str</code> name that is either <code>'trackFile'</code> for the single track file process\nor <code>'trackFiles'</code> for the app page that handles more than one track file at\na time.</p>\n\n<pre><code>uploaderKey\n</code></pre>\n\n<p>A unique identifier for the uploader key component, usually set to\n<code>'uploaderKey'</code> but can be any arbitrary name.  This value must match the\n<code>file_uploader(..., key=uploaderKey,...)</code> value.</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">filesObject</span><span class=\"p\">:</span> <span class=\"nb\">str</span>, </span><span class=\"param\"><span class=\"n\">uploaderKey</span><span class=\"p\">:</span> <span class=\"nb\">str</span> <span class=\"o\">=</span> <span class=\"s1\">&#39;uploaderKey&#39;</span></span><span class=\"return-annotation\">):</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.appcommon.displayTrackOnMap", "modulename": "ssscoring.appcommon", "qualname": "displayTrackOnMap", "kind": "function", "doc": "<p>Displays a track map drawn using PyDeck.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>deck\n</code></pre>\n\n<p>A PyDeck initialized with map layers.</p>\n\n<pre><code>displayScore\n</code></pre>\n\n<p>If <code>True</code>, display the max score point; else display the max speed point.</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">deck</span><span class=\"p\">:</span> <span class=\"n\">pydeck</span><span class=\"o\">.</span><span class=\"n\">bindings</span><span class=\"o\">.</span><span class=\"n\">deck</span><span class=\"o\">.</span><span class=\"n\">Deck</span>, </span><span class=\"param\"><span class=\"n\">displayScore</span><span class=\"o\">=</span><span class=\"kc\">True</span></span><span class=\"return-annotation\">):</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.appcommon.displayDZCoordinates", "modulename": "ssscoring.appcommon", "qualname": "displayDZCoordinates", "kind": "function", "doc": "<p>Display the DZ coordinates in a dialog if one is selected in the drop zones\nselection box.  The selection is stored in the  <code>st.session_state.currentDropZone</code>\nvariable.  If a valid name is available, the latitude and longitude are\ndisplayed.  If <code>None</code> or invalid, a notification dialog is displayed.</p>\n\n<p>The corresponding UI button is only enabled if the user selected a valid DZ,\notherwise the button is disabled.</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"return-annotation\">):</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.appcommon.setSideBarAndMain", "modulename": "ssscoring.appcommon", "qualname": "setSideBarAndMain", "kind": "function", "doc": "<p>Set all the interactive and navigational components for the app's side bar.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>icon\n</code></pre>\n\n<p>A meaningful Emoji associated with the the side bar's title.</p>\n\n<pre><code>singleTrack\n</code></pre>\n\n<p>A flag for allowing selection of a single or multiple track files in the\ncorresponding selector component.  Determines whether the side bar is used\nfor the single- or multiple selection application.</p>\n\n<pre><code>selectDZState\n</code></pre>\n\n<p>A callback for the drop zone selector selection box, affected by events in\nthe main application.</p>\n\n<h2 id=\"notes\">Notes</h2>\n\n<p>All the aplication level values associated with the components and\nselections from the side bar are stored in <code>st.session_state</code> and visible\nacross the whole application.</p>\n\n<p><strong>Do not</strong> cache calls to <code>ssscoring.appcommon.setSideBarAndMain()</code> because\nthis can result in unpredictable behavior since the cache may never be\ncleared until application reload.</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">icon</span><span class=\"p\">:</span> <span class=\"nb\">str</span>, </span><span class=\"param\"><span class=\"n\">singleTrack</span><span class=\"p\">:</span> <span class=\"nb\">bool</span>, </span><span class=\"param\"><span class=\"n\">selectDZState</span></span><span class=\"return-annotation\">):</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.appcommon.setSideBarDeprecated", "modulename": "ssscoring.appcommon", "qualname": "setSideBarDeprecated", "kind": "function", "doc": "<p>Set a disabled version of the sidebar to maintain UX compatibility with the\nactual app, used when the main screen is configured to display an end-user\nmessage like \"we moved to a new domain.\"</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>icon\n</code></pre>\n\n<p>A meaningful Emoji associated with the the side bar's title.</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">icon</span><span class=\"p\">:</span> <span class=\"nb\">str</span></span><span class=\"return-annotation\">):</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.calc", "modulename": "ssscoring.calc", "kind": "module", "doc": "<p>Functions and logic for analyzing and manipulating FlySight dataframes.</p>\n"}, {"fullname": "ssscoring.calc.isValidMinimumAltitude", "modulename": "ssscoring.calc", "qualname": "isValidMinimumAltitude", "kind": "function", "doc": "<p>Reports whether an <code>altitude</code> is below the IPC and USPA valid parameters,\nor within <code>BREAKOFF_ALTITUDE</code> and <code>PERFORMACE_WINDOW_LENGTH</code>.  In invalid\naltitude doesn't invalidate a FlySight data file.  This function can be used\nfor generating warnings.  The stock FlySightViewer scores a speed jump even\nif the exit was below the minimum altitude.</p>\n\n<p>See:  FAI Competition Rules Speed Skydiving section 5.3 for details.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>altitude\n</code></pre>\n\n<p>An altitude in meters, calculated as data.hMSL - DZ altitude.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p><code>True</code> if the altitude is valid.</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">altitude</span><span class=\"p\">:</span> <span class=\"nb\">float</span></span><span class=\"return-annotation\">) -> <span class=\"nb\">bool</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.calc.isValidMaximumAltitude", "modulename": "ssscoring.calc", "qualname": "isValidMaximumAltitude", "kind": "function", "doc": "<p>Reports whether an <code>altitude</code> is above the maximum altitude allowed by the\nrules.</p>\n\n<p>See:  FAI Competition Rules Speed Skydiving section 5.3 for details.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>altitude\n</code></pre>\n\n<p>An altitude in meters, calculated as data.hMSL - DZ altitude.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p><code>True</code> if the altitude is valid.</p>\n\n<h2 id=\"see\">See</h2>\n\n<p><code>ssscoring.constants.MAX_ALTITUDE_FT</code>\n<code>ssscoring.constants.MAX_ALTITUDE_METERS</code></p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">altitude</span><span class=\"p\">:</span> <span class=\"nb\">float</span></span><span class=\"return-annotation\">) -> <span class=\"nb\">bool</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.calc.isValidJumpISC", "modulename": "ssscoring.calc", "qualname": "isValidJumpISC", "kind": "function", "doc": "<p><strong>DEPRECATED</strong> - Validates the jump according to ISC/FAI/USPA competition rules.  A jump is\nvalid when the speed accuracy parameter is less than 3 m/s for the whole\nvalidation window duration.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>data : pd.DataFramce\n</code></pre>\n\n<p>Jumnp data in SSScoring format\n    window : ssscoring.PerformanceWindow\nPerformance window start, end values in named tuple format</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p><code>True</code> if the jump is valid according to ISC/FAI/USPA rules.</p>\n", "signature": "<span class=\"signature pdoc-code multiline\">(<span class=\"param\">\t<span class=\"n\">data</span><span class=\"p\">:</span> <span class=\"n\">pandas</span><span class=\"o\">.</span><span class=\"n\">core</span><span class=\"o\">.</span><span class=\"n\">frame</span><span class=\"o\">.</span><span class=\"n\">DataFrame</span>,</span><span class=\"param\">\t<span class=\"n\">window</span><span class=\"p\">:</span> <span class=\"n\">ssscoring</span><span class=\"o\">.</span><span class=\"n\">datatypes</span><span class=\"o\">.</span><span class=\"n\">PerformanceWindow</span></span><span class=\"return-annotation\">) -> <span class=\"nb\">bool</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.calc.validateJumpISC", "modulename": "ssscoring.calc", "qualname": "validateJumpISC", "kind": "function", "doc": "<p>Validates the jump according to ISC/FAI/USPA competition rules.  A jump is\nvalid when the speed accuracy parameter is less than 3 m/s for the whole\nvalidation window duration.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>data : pd.DataFramce\n</code></pre>\n\n<p>Jumnp data in SSScoring format\n    window : ssscoring.PerformanceWindow\nPerformance window start, end values in named tuple format</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<ul>\n<li><code>JumpStatus.OK</code> if <code>data</code> reflects a valid jump according to ISC rules,\nwhere all speed accuracy values &lt; 'SPEED_ACCURACY_THRESHOLD'.</li>\n<li><code>JumpStatus.SPEED_ACCURACY_EXCEEDS_LIMIT' if</code>data` has one or more values\nwithin the validation window with a value &gt;= 'SPEED_ACCURACY_THRESHOLD'.</li>\n</ul>\n\n<h2 id=\"raises\">Raises</h2>\n\n<p><code>SSScoringError' if</code>data` has a length of zero or it's not initialized.</p>\n", "signature": "<span class=\"signature pdoc-code multiline\">(<span class=\"param\">\t<span class=\"n\">data</span><span class=\"p\">:</span> <span class=\"n\">pandas</span><span class=\"o\">.</span><span class=\"n\">core</span><span class=\"o\">.</span><span class=\"n\">frame</span><span class=\"o\">.</span><span class=\"n\">DataFrame</span>,</span><span class=\"param\">\t<span class=\"n\">window</span><span class=\"p\">:</span> <span class=\"n\">ssscoring</span><span class=\"o\">.</span><span class=\"n\">datatypes</span><span class=\"o\">.</span><span class=\"n\">PerformanceWindow</span></span><span class=\"return-annotation\">) -> <span class=\"n\">ssscoring</span><span class=\"o\">.</span><span class=\"n\">datatypes</span><span class=\"o\">.</span><span class=\"n\">JumpStatus</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.calc.calculateDistance", "modulename": "ssscoring.calc", "qualname": "calculateDistance", "kind": "function", "doc": "<p>Calculate the distance between two terrestrial coordinates points.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>start\n</code></pre>\n\n<p>A latitude, longitude tuple of floating point numbers.</p>\n\n<pre><code>end\n</code></pre>\n\n<p>A latitude, longitude tuple of floating point numbers.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p>The distance, in meters, between both points.</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">start</span><span class=\"p\">:</span> <span class=\"nb\">tuple</span>, </span><span class=\"param\"><span class=\"n\">end</span><span class=\"p\">:</span> <span class=\"nb\">tuple</span></span><span class=\"return-annotation\">) -> <span class=\"nb\">float</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.calc.convertFlySight2SSScoring", "modulename": "ssscoring.calc", "qualname": "convertFlySight2SSScoring", "kind": "function", "doc": "<p>Converts a raw dataframe initialized from a FlySight CSV file into the\nSSScoring file format.  The SSScoring format uses more descriptive column\nheaders, adds the altitude in feet, and uses UNIX time instead of an ISO\nstring.</p>\n\n<p>If both <code>altitudeDZMeters</code> and <code>altitudeDZFt</code> are zero then hMSL is used.\nOtherwise, this function adjusts the effective altitude with the value.  If\nboth meters and feet values are set this throws an error.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>rawData : pd.DataFrame\n</code></pre>\n\n<p>FlySight CSV input as a dataframe</p>\n\n<pre><code>altitudeDZMeters : float\n</code></pre>\n\n<p>Drop zone height above MSL</p>\n\n<pre><code>altitudeDZFt\n</code></pre>\n\n<p>Drop zone altitudde above MSL</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p>A dataframe in SSScoring format, featuring these columns:</p>\n\n<ul>\n<li>timeUnix</li>\n<li>altitudeMSL</li>\n<li>altitudeAGL</li>\n<li>altitudeMSLFt</li>\n<li>altitudeAGLFt</li>\n<li>vMetersPerSecond</li>\n<li>vKMh (km/h)</li>\n<li>vAccelMS2 (m/s\u00b2)</li>\n<li>speedAccuracy (ignore; see ISC documentation)</li>\n<li>hMetersPerSecond</li>\n<li>hKMh (km/h)</li>\n<li>latitude</li>\n<li>longitude</li>\n<li>verticalAccuracy</li>\n<li>speedAccuracyISC</li>\n</ul>\n\n<h2 id=\"errors\">Errors</h2>\n\n<p><code>SSScoringError</code> if the DZ altitude is set in both meters and feet.</p>\n", "signature": "<span class=\"signature pdoc-code multiline\">(<span class=\"param\">\t<span class=\"n\">rawData</span><span class=\"p\">:</span> <span class=\"n\">pandas</span><span class=\"o\">.</span><span class=\"n\">core</span><span class=\"o\">.</span><span class=\"n\">frame</span><span class=\"o\">.</span><span class=\"n\">DataFrame</span>,</span><span class=\"param\">\t<span class=\"n\">altitudeDZMeters</span><span class=\"o\">=</span><span class=\"mf\">0.0</span>,</span><span class=\"param\">\t<span class=\"n\">altitudeDZFt</span><span class=\"o\">=</span><span class=\"mf\">0.0</span></span><span class=\"return-annotation\">):</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.calc.getSpeedSkydiveFrom", "modulename": "ssscoring.calc", "qualname": "getSpeedSkydiveFrom", "kind": "function", "doc": "<p>Take the skydive dataframe and get the speed skydiving data:</p>\n\n<ul>\n<li>Exit</li>\n<li>Speed skydiving window</li>\n<li>Drops data before exit and below breakoff altitude</li>\n</ul>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>data : pd.DataFrame\n</code></pre>\n\n<p>Jump data in SSScoring format</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p>A tuple of two elements:</p>\n\n<ul>\n<li>A named tuple with performance and validation window data</li>\n<li>A dataframe featuring only speed skydiving data</li>\n</ul>\n\n<p>Warm up FlySight files and non-speed skydiving files may return invalid\nvalues:</p>\n\n<ul>\n<li><code>None</code> for the <code>PerformanceWindow</code> instance</li>\n<li><code>data</code>, most likely empty</li>\n</ul>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">data</span><span class=\"p\">:</span> <span class=\"n\">pandas</span><span class=\"o\">.</span><span class=\"n\">core</span><span class=\"o\">.</span><span class=\"n\">frame</span><span class=\"o\">.</span><span class=\"n\">DataFrame</span></span><span class=\"return-annotation\">) -> <span class=\"nb\">tuple</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.calc.jumpAnalysisTable", "modulename": "ssscoring.calc", "qualname": "jumpAnalysisTable", "kind": "function", "doc": "<p>Generates the HCD jump analysis table, with speed data at 5-second intervals\nafter exit.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>data : pd.DataFrame\n</code></pre>\n\n<p>Jump data in SSScoring format</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p>A tuple with a pd.DataFrame and the max speed recorded for the jump:</p>\n\n<ul>\n<li>A table dataframe with time and speed</li>\n<li>a floating point number</li>\n</ul>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">data</span><span class=\"p\">:</span> <span class=\"n\">pandas</span><span class=\"o\">.</span><span class=\"n\">core</span><span class=\"o\">.</span><span class=\"n\">frame</span><span class=\"o\">.</span><span class=\"n\">DataFrame</span></span><span class=\"return-annotation\">) -> <span class=\"n\">pandas</span><span class=\"o\">.</span><span class=\"n\">core</span><span class=\"o\">.</span><span class=\"n\">frame</span><span class=\"o\">.</span><span class=\"n\">DataFrame</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.calc.dropNonSkydiveDataFrom", "modulename": "ssscoring.calc", "qualname": "dropNonSkydiveDataFrom", "kind": "function", "doc": "<p>Discards all data rows before maximum altitude, and all \"negative\" altitude\nrows because we don't skydive underground (FlySight bug?).</p>\n\n<p>This is a more accurate mean velocity calculation from a physics point of\nview, but it differs from the ISC definition using in scoring - which, if we\nget technical, is the one that counts.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>data : pd.DataFrame\n</code></pre>\n\n<p>Jump data in SSScoring format (headers differ from FlySight format)</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p>The jump data for the skydive</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">data</span><span class=\"p\">:</span> <span class=\"n\">pandas</span><span class=\"o\">.</span><span class=\"n\">core</span><span class=\"o\">.</span><span class=\"n\">frame</span><span class=\"o\">.</span><span class=\"n\">DataFrame</span></span><span class=\"return-annotation\">) -> <span class=\"n\">pandas</span><span class=\"o\">.</span><span class=\"n\">core</span><span class=\"o\">.</span><span class=\"n\">frame</span><span class=\"o\">.</span><span class=\"n\">DataFrame</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.calc.calcScoreMeanVelocity", "modulename": "ssscoring.calc", "qualname": "calcScoreMeanVelocity", "kind": "function", "doc": "<p>Calculates the speeds over a 3-second interval as the mean of all the speeds\nrecorded within that 3-second window and resolves the maximum speed.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>data\n</code></pre>\n\n<p>A <code>pd.dataframe</code> with speed run data.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p>A <code>tuple</code> with the best score throughout the speed run, and a dicitionary\nof the meanVSpeed:spotInTime used in determining the exact scoring speed\nat every datat point during the speed run.</p>\n\n<h2 id=\"notes\">Notes</h2>\n\n<p>This implementation uses iteration instead of binning/factorization because\nsome implementers may be unfamiliar with data manipulation in dataframes\nand this is a critical function that may be under heavy review.  Future\nversions may revert to dataframe and series/np.array factorization.</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">data</span><span class=\"p\">:</span> <span class=\"n\">pandas</span><span class=\"o\">.</span><span class=\"n\">core</span><span class=\"o\">.</span><span class=\"n\">frame</span><span class=\"o\">.</span><span class=\"n\">DataFrame</span></span><span class=\"return-annotation\">) -> <span class=\"nb\">tuple</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.calc.calcScoreISC", "modulename": "ssscoring.calc", "qualname": "calcScoreISC", "kind": "function", "doc": "<p>Calculates the speeds over a 3-second interval as the ds/dt and dt is the\nis a 3-second sliding interval from exit.  The window slider moves along the\n<code>plotTime</code> axis in the dataframe.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>data\n</code></pre>\n\n<p>A <code>pd.dataframe</code> with speed run data.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p>A <code>tuple</code> with the best score throughout the speed run, and a dicitionary\nof the meanVSpeed:spotInTime used in determining the exact scoring speed\nat every datat point during the speed run.</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">data</span><span class=\"p\">:</span> <span class=\"n\">pandas</span><span class=\"o\">.</span><span class=\"n\">core</span><span class=\"o\">.</span><span class=\"n\">frame</span><span class=\"o\">.</span><span class=\"n\">DataFrame</span></span><span class=\"return-annotation\">) -> <span class=\"nb\">tuple</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.calc.processJump", "modulename": "ssscoring.calc", "qualname": "processJump", "kind": "function", "doc": "<p>Take a dataframe in SSScoring format and process it for display.  It\nserializes all the steps that would be taken from the ssscoring module, but\nincludes some text/HTML data in the output.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>data: pd.DataFrame\n</code></pre>\n\n<p>A dataframe in SSScoring format</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p>A <code>JumpResults</code> named tuple with these items:</p>\n\n<ul>\n<li><code>score</code> speed score</li>\n<li><code>maxSpeed</code> maximum speed during the jump</li>\n<li><code>scores</code> a Series of every 3-second window scores from exit to breakoff</li>\n<li><code>data</code> an updated SSScoring dataframe <code>plotTime</code>, where 0 = exit, used\nfor plotting</li>\n<li><code>window</code> a named tuple with the exit, breakoff, and validation window\naltitudes</li>\n<li><code>table</code> a dataframe featuring the speeds and altitudes at 5-sec intervals</li>\n<li><code>color</code> a string that defines the color for the jump result; possible\nvalues are _green_ for valid jump, _red_ for invalid jump, per ISC rules</li>\n<li><code>result</code> a string with the legend of _valid_ or _invalid_ jump</li>\n</ul>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">data</span><span class=\"p\">:</span> <span class=\"n\">pandas</span><span class=\"o\">.</span><span class=\"n\">core</span><span class=\"o\">.</span><span class=\"n\">frame</span><span class=\"o\">.</span><span class=\"n\">DataFrame</span></span><span class=\"return-annotation\">) -> <span class=\"n\">ssscoring</span><span class=\"o\">.</span><span class=\"n\">datatypes</span><span class=\"o\">.</span><span class=\"n\">JumpResults</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.calc.getFlySightDataFromCSVBuffer", "modulename": "ssscoring.calc", "qualname": "getFlySightDataFromCSVBuffer", "kind": "function", "doc": "<p>Ingress a buffer with known FlySight or SkyTrax file data for SSScoring\nprocessing.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>buffer\n</code></pre>\n\n<p>A binary data buffer, bag of bytes, containing a known FlySight track file.</p>\n\n<pre><code>bufferName\n</code></pre>\n\n<p>An arbitrary name for the buffer of type <code>str</code>.  It's used for constructing\nthe full buffer tag value for human identification.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p>A <code>tuple</code> with two items:\n    - <code>rawData</code> - a dataframe representation of the CSV with the original\n      headers but without the data type header\n    - <code>tag</code> - a string with an identifying tag derived from the path name\n      and file version in the form <code>some name:vX</code>.  It uses the current\n      path as metadata to infer the name.  There's no semantics enforcement.</p>\n\n<h2 id=\"raises\">Raises</h2>\n\n<p><code>SSScoringError</code> if the CSV file is invalid in any way.</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">buffer</span><span class=\"p\">:</span> <span class=\"nb\">bytes</span>, </span><span class=\"param\"><span class=\"n\">bufferName</span><span class=\"p\">:</span> <span class=\"nb\">str</span></span><span class=\"return-annotation\">) -> <span class=\"nb\">tuple</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.calc.getFlySightDataFromCSVFileName", "modulename": "ssscoring.calc", "qualname": "getFlySightDataFromCSVFileName", "kind": "function", "doc": "<p>Ingress a known FlySight or SkyTrax file into memory for SSScoring\nprocessing.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>jumpFile\n</code></pre>\n\n<p>A string or <code>pathlib.Path</code> object; can be a relative or an asbolute path.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p>A <code>tuple</code> with two items:\n    - <code>rawData</code> - a dataframe representation of the CSV with the original\n      headers but without the data type header\n    - <code>tag</code> - a string with an identifying tag derived from the path name\n      and file version in the form <code>some name:vX</code>.  It uses the current\n      path as metadata to infer the name.  There's no semantics enforcement.</p>\n\n<h2 id=\"raises\">Raises</h2>\n\n<p><code>SSScoringError</code> if the CSV file is invalid in any way.</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">jumpFile</span></span><span class=\"return-annotation\">) -> <span class=\"nb\">tuple</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.calc.processAllJumpFiles", "modulename": "ssscoring.calc", "qualname": "processAllJumpFiles", "kind": "function", "doc": "<p>Process all jump files in a list of valid FlySight files.  Returns a\ndictionary of jump results with a human-readable version of the file name.\nThe <code>jumpFiles</code> list can be generated by hand or the output of the\n<code>ssscoring.fs1.getAllSpeedJumpFilesFrom</code> called to operate on a data lake.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>jumpFiles\n</code></pre>\n\n<p>A list of file things that could represent one of these:</p>\n\n<ul>\n<li>file things relative or absolute path names to individual FlySight CSV\nfiles.</li>\n<li>A specialization of BytesIO, such as the bags of bytes that Streamlit.io\ngenerates after uploading and reading a file into the Streamlit\nenvironment</li>\n</ul>\n\n<pre><code>altitudeDZMeters : float\n</code></pre>\n\n<p>Drop zone height above MSL</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<pre><code>dict\n</code></pre>\n\n<p>A dictionary of jump results.  The key is a human-readable version of a\n<code>jumpFile</code> name with the extension, path, and extraneous spaces eliminated\nor replaced by appropriate characters.  File names use Unicode, so accents\nand non-ANSI characters are allowed in file names.</p>\n\n<h2 id=\"raises\">Raises</h2>\n\n<p><code>SSScoringError</code> if the jumpFiles object is empty, or if the individual\nobjects in the list aren't <code>BytesIO</code>, file name strings, or <code>Path</code>\ninstances.</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">jumpFiles</span><span class=\"p\">:</span> <span class=\"nb\">list</span>, </span><span class=\"param\"><span class=\"n\">altitudeDZMeters</span><span class=\"o\">=</span><span class=\"mf\">0.0</span></span><span class=\"return-annotation\">) -> <span class=\"nb\">dict</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.calc.aggregateResults", "modulename": "ssscoring.calc", "qualname": "aggregateResults", "kind": "function", "doc": "<p>Aggregate all the results in a table fashioned after Marco Hepp's and Nklas\nDaniel's score tracking data.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>jumpResults: dict\n</code></pre>\n\n<p>A dictionary of jump results, in which each result corresponds to a FlySight\nfile name.  See <code>ssscoring.processAllJumpFiles</code> for details.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p>A dataframe featuring these columns:</p>\n\n<ul>\n<li>Score</li>\n<li>Speeds at 5, 10, 15, 20, and 25 second tranches</li>\n<li>Final time contemplated in the analysis</li>\n<li>Max speed</li>\n</ul>\n\n<p>The dataframe rows are identified by the human readable jump file name.</p>\n\n<h2 id=\"raises\">Raises</h2>\n\n<p><code>SSSCoringError</code> if the <code>jumpResults</code> object is empty.</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">jumpResults</span><span class=\"p\">:</span> <span class=\"nb\">dict</span></span><span class=\"return-annotation\">) -> <span class=\"n\">pandas</span><span class=\"o\">.</span><span class=\"n\">core</span><span class=\"o\">.</span><span class=\"n\">frame</span><span class=\"o\">.</span><span class=\"n\">DataFrame</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.calc.roundedAggregateResults", "modulename": "ssscoring.calc", "qualname": "roundedAggregateResults", "kind": "function", "doc": "<p>Aggregate all the results in a table fashioned after Marco Hepp's and Nklas\nDaniel's score tracking data.  All speed results are rounded at <code>n &gt; x.5</code>\nfor any value.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>aggregate: pd.DataFrame\n</code></pre>\n\n<p>A dataframe output of <code>ssscoring.fs1.aggregateResults</code>.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p>A dataframe featuring the <strong>rounded values</strong> for these columns:</p>\n\n<ul>\n<li>Score</li>\n<li>Speeds at 5, 10, 15, 20, and 25 second tranches</li>\n<li>Max speed</li>\n</ul>\n\n<p>The <code>finalTime</code> column is ignored.</p>\n\n<p>The dataframe rows are identified by the human readable jump file name.</p>\n\n<p>This is a less precise version of the <code>ssscoring.aggregateResults</code>\ndataframe, useful during training to keep rounded results available for\nreview.</p>\n\n<h2 id=\"raises\">Raises</h2>\n\n<p><code>SSSCoringError</code> if the <code>jumpResults</code> object is empty.</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">aggregate</span><span class=\"p\">:</span> <span class=\"n\">pandas</span><span class=\"o\">.</span><span class=\"n\">core</span><span class=\"o\">.</span><span class=\"n\">frame</span><span class=\"o\">.</span><span class=\"n\">DataFrame</span></span><span class=\"return-annotation\">) -> <span class=\"n\">pandas</span><span class=\"o\">.</span><span class=\"n\">core</span><span class=\"o\">.</span><span class=\"n\">frame</span><span class=\"o\">.</span><span class=\"n\">DataFrame</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.calc.collateAnglesByTimeFromExit", "modulename": "ssscoring.calc", "qualname": "collateAnglesByTimeFromExit", "kind": "function", "doc": "<p>Collate all the angles by time from the <code>jumpResults</code> into a dataframe that\nfeatures the jump tag as index, the time tranches and the angles at each\ntime tranche.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>jumpResults: dict\n</code></pre>\n\n<p>A dictionary of jump results, in which each result corresponds to a FlySight\nfile name.  See <code>ssscoring.processAllJumpFiles</code> for details.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p>A dataframe featuring these columns:</p>\n\n<ul>\n<li>Score</li>\n<li>Angles at 5, 10, 15, 20, and 25 second tranches</li>\n<li>Final time contemplated in the analysis</li>\n</ul>\n\n<h2 id=\"raises\">Raises</h2>\n\n<p><code>SSSCoringError</code> if the <code>jumpResults</code> object is empty.</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">jumpResults</span><span class=\"p\">:</span> <span class=\"nb\">dict</span></span><span class=\"return-annotation\">) -> <span class=\"n\">pandas</span><span class=\"o\">.</span><span class=\"n\">core</span><span class=\"o\">.</span><span class=\"n\">frame</span><span class=\"o\">.</span><span class=\"n\">DataFrame</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.calc.totalResultsFrom", "modulename": "ssscoring.calc", "qualname": "totalResultsFrom", "kind": "function", "doc": "<p>Calculates the total and mean speeds for an aggregation of speed jumps.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>aggregate: pd.DataFrame\n</code></pre>\n\n<p>The aggregate results dataframe resulting from calling <code>ssscoring.aggregateResults</code>\nwith valid results.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p>A dataframe with one row and two columns:</p>\n\n<ul>\n<li>totalSpeed ::= the sum of all speeds in the aggregated results</li>\n<li>meanSpeed ::= the mean of all speeds</li>\n<li>maxSpeed := the absolute max speed over the speed runs set</li>\n<li>meanSpeedSTD := scored speeds standar deviation</li>\n<li>maxScore ::= the max score among all the speed scores</li>\n<li>maxScoreSTD := the max scores standard deviation</li>\n</ul>\n\n<h2 id=\"raises\">Raises</h2>\n\n<p><code>AttributeError</code> if aggregate is an empty dataframe or <code>None</code>, or if the\n<code>aggregate</code> dataframe doesn't conform to the output of <code>ssscoring.aggregateResults</code>.</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">aggregate</span><span class=\"p\">:</span> <span class=\"n\">pandas</span><span class=\"o\">.</span><span class=\"n\">core</span><span class=\"o\">.</span><span class=\"n\">frame</span><span class=\"o\">.</span><span class=\"n\">DataFrame</span></span><span class=\"return-annotation\">) -> <span class=\"n\">pandas</span><span class=\"o\">.</span><span class=\"n\">core</span><span class=\"o\">.</span><span class=\"n\">frame</span><span class=\"o\">.</span><span class=\"n\">DataFrame</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.cli", "modulename": "ssscoring.cli", "kind": "module", "doc": "<p>Command line tools package.</p>\n"}, {"fullname": "ssscoring.cli.die", "modulename": "ssscoring.cli", "qualname": "die", "kind": "function", "doc": "<p>Display an end-user <code>message</code> and exit the program with <code>exitCode</code>.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>message\n</code></pre>\n\n<p>A string, most often with a descriptive error message.</p>\n\n<pre><code>exitCode\n</code></pre>\n\n<p>An exit code, where <code>0</code> is normal exit, and any other value is an error\ncondition.</p>\n\n<pre><code>isUnitTest\n</code></pre>\n\n<p>A Boolean; if <code>True</code>, the program returns the value of <code>exitCode</code> to the\ncaller, otherwise it terminates with <code>sys.exit(exitCode)</code>.</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">message</span><span class=\"p\">:</span> <span class=\"nb\">str</span>, </span><span class=\"param\"><span class=\"n\">exitCode</span><span class=\"p\">:</span> <span class=\"nb\">int</span>, </span><span class=\"param\"><span class=\"n\">isUnitTest</span><span class=\"o\">=</span><span class=\"kc\">False</span></span><span class=\"return-annotation\">) -> <span class=\"nb\">int</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.cli.ssscore", "modulename": "ssscoring.cli", "qualname": "ssscore", "kind": "function", "doc": "<p>Process all the speed skydiving files contained in <code>dataLakeSpec</code>.  This\nfunction implements the business logic for the <code>/usr/local/bin/ssscore</code>\ncommand.  See <code>pyproject.toml</code> for command details.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>elevation\n</code></pre>\n\n<p>The drop zone elevation MSL in feet.</p>\n\n<pre><code>trainingOutput\n</code></pre>\n\n<p>If <code>True</code>, output will use rounded values.</p>\n\n<pre><code>dataLake\n</code></pre>\n\n<p>Command line argument with the path to the data lake.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p>The number of jump results from processing all the FlySight files in the\ndata lake.</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">elevation</span><span class=\"p\">:</span> <span class=\"nb\">float</span>, </span><span class=\"param\"><span class=\"n\">trainingOutput</span><span class=\"p\">:</span> <span class=\"nb\">bool</span>, </span><span class=\"param\"><span class=\"n\">dataLake</span><span class=\"p\">:</span> <span class=\"nb\">str</span></span><span class=\"return-annotation\">) -> <span class=\"nb\">int</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.constants", "modulename": "ssscoring.constants", "kind": "module", "doc": "<p>Constants module and definitions.</p>\n\n<p><strong>All measurements are expressed in meters unless noted otherwise.</strong></p>\n"}, {"fullname": "ssscoring.constants.BREAKOFF_ALTITUDE", "modulename": "ssscoring.constants", "qualname": "BREAKOFF_ALTITUDE", "kind": "variable", "doc": "<p>Breakoff altitude or hard deck.</p>\n", "default_value": "1707.0"}, {"fullname": "ssscoring.constants.DEFAULT_PLOT_INCREMENT", "modulename": "ssscoring.constants", "qualname": "DEFAULT_PLOT_INCREMENT", "kind": "variable", "doc": "<p>Used to adjust the plot's max scale to <code>score</code> + <code>DEFAULT_PLOT_INCREMENT</code> so\nthat the whole jump progression is visible in the plot.</p>\n", "default_value": "75.0"}, {"fullname": "ssscoring.constants.DEFAULT_PLOT_MAX_V_SCALE", "modulename": "ssscoring.constants", "qualname": "DEFAULT_PLOT_MAX_V_SCALE", "kind": "variable", "doc": "<p>Default speed plot scale max is set to 550 km/h, but there is evidence it can\nbe higher and adjusted on-the-fly based on jump results.</p>\n", "default_value": "550.0"}, {"fullname": "ssscoring.constants.DEFAULT_SPEED_ACCURACY_SCALE", "modulename": "ssscoring.constants", "qualname": "DEFAULT_SPEED_ACCURACY_SCALE", "kind": "variable", "doc": "<p>Default speed accuracy scale set to 5, to make it visible in plots.  This value\nwas chosen because the valid threshold is accuracy &lt; 3.0, and this makes most\nvalues visible without intefering with other curves in the same plot.</p>\n\n<h1 id=\"see\">See</h1>\n\n<pre><code>ssscoring.notebook\nssscoring.appcommon\n</code></pre>\n", "default_value": "5.0"}, {"fullname": "ssscoring.constants.DEG_IN_RADIANS", "modulename": "ssscoring.constants", "qualname": "DEG_IN_RADIANS", "kind": "variable", "doc": "<p>\u03c0/180\u00ba</p>\n", "default_value": "0.017453292519943295"}, {"fullname": "ssscoring.constants.DZ_DIRECTORY", "modulename": "ssscoring.constants", "qualname": "DZ_DIRECTORY", "kind": "variable", "doc": "<p>The CSV file database dump of the drop zones directory.</p>\n", "default_value": "&#x27;drop-zones-loc-elev.csv&#x27;"}, {"fullname": "ssscoring.constants.EXIT_SPEED", "modulename": "ssscoring.constants", "qualname": "EXIT_SPEED", "kind": "variable", "doc": "<p>Guesstimate of the exit speed; ~g</p>\n", "default_value": "10.0"}, {"fullname": "ssscoring.constants.FLYSIGHT_1_HEADER", "modulename": "ssscoring.constants", "qualname": "FLYSIGHT_1_HEADER", "kind": "variable", "doc": "<p>FlySight v1 CSV file headers.</p>\n", "default_value": "{&#x27;lon&#x27;, &#x27;velN&#x27;, &#x27;lat&#x27;, &#x27;gpsFix&#x27;, &#x27;hMSL&#x27;, &#x27;cAcc&#x27;, &#x27;hAcc&#x27;, &#x27;heading&#x27;, &#x27;velD&#x27;, &#x27;sAcc&#x27;, &#x27;numSV&#x27;, &#x27;time&#x27;, &#x27;velE&#x27;, &#x27;vAcc&#x27;}"}, {"fullname": "ssscoring.constants.FLYSIGHT_2_HEADER", "modulename": "ssscoring.constants", "qualname": "FLYSIGHT_2_HEADER", "kind": "variable", "doc": "<p>FlySight v1 CSV file headers.  Unlike other constants, this is a <code>tuple</code> instead\nof a <code>set</code> because the code manipulates the headers/columns during file ingress.</p>\n", "default_value": "(&#x27;GNSS&#x27;, &#x27;time&#x27;, &#x27;lat&#x27;, &#x27;lon&#x27;, &#x27;hMSL&#x27;, &#x27;velN&#x27;, &#x27;velE&#x27;, &#x27;velD&#x27;, &#x27;hAcc&#x27;, &#x27;vAcc&#x27;, &#x27;sAcc&#x27;, &#x27;numSV&#x27;)"}, {"fullname": "ssscoring.constants.FLYSIGHT_FILE_ENCODING", "modulename": "ssscoring.constants", "qualname": "FLYSIGHT_FILE_ENCODING", "kind": "variable", "doc": "<p>File encoding as it comes raw from the FlySight device.</p>\n", "default_value": "&#x27;utf-8&#x27;"}, {"fullname": "ssscoring.constants.FT_IN_M", "modulename": "ssscoring.constants", "qualname": "FT_IN_M", "kind": "variable", "doc": "<p>Number of feet in a meter.</p>\n", "default_value": "3.2808"}, {"fullname": "ssscoring.constants.IGNORE_LIST", "modulename": "ssscoring.constants", "qualname": "IGNORE_LIST", "kind": "variable", "doc": "<p>Internal use - list of files to be ignored during bulk file processing in the\ndata lake (e.g. <code>./data</code>).</p>\n", "default_value": "[&#x27;.ipynb_checkpoints&#x27;]"}, {"fullname": "ssscoring.constants.KMH_AS_MS", "modulename": "ssscoring.constants", "qualname": "KMH_AS_MS", "kind": "variable", "doc": "<p>km/h as m/s</p>\n", "default_value": "3.6"}, {"fullname": "ssscoring.constants.LAST_TIME_TRANCHE", "modulename": "ssscoring.constants", "qualname": "LAST_TIME_TRANCHE", "kind": "variable", "doc": "<p>Times &gt; 25 s are irrelevant because it means that the speed skydiver flew at\nvSpeed &lt; 400 km/h.</p>\n", "default_value": "25.0"}, {"fullname": "ssscoring.constants.MAX_VALID_ELEVATION", "modulename": "ssscoring.constants", "qualname": "MAX_VALID_ELEVATION", "kind": "variable", "doc": "<p>Max valid elevation allowed in the FlySight or FlySsight 2 time series.  Speed\nskydivers are known to jump from as high as <code>MAX_VALID_ELEVATION</code> without O2.\nThe SSScoring algorithms eliminate all data entries where elevation AGL &gt; <code>MAX_VALID_ELEVATION</code>\nbefore processing the jump for scoring.  That's because occasional FlySight\nerrors caused by intermittent GPS signal loss and invalid GPS readings when the\nskydiver sits under an airplane's wing during the climb to altitude and other\nfactors.</p>\n", "default_value": "4602.0"}, {"fullname": "ssscoring.constants.MAX_VALID_ELEVATION_FT", "modulename": "ssscoring.constants", "qualname": "MAX_VALID_ELEVATION_FT", "kind": "variable", "doc": "<p>Same as <code>MAX_VALID_ELEVATION</code>, in ft.</p>\n", "default_value": "15094.56"}, {"fullname": "ssscoring.constants.MAX_ALTITUDE_FT", "modulename": "ssscoring.constants", "qualname": "MAX_ALTITUDE_FT", "kind": "variable", "doc": "<p>Maximum exit altitude AGL according to FAI Competition Rules Speed Skydiving\nsection 5.3.</p>\n", "default_value": "14000.0"}, {"fullname": "ssscoring.constants.MAX_ALTITUDE_METERS", "modulename": "ssscoring.constants", "qualname": "MAX_ALTITUDE_METERS", "kind": "variable", "doc": "<h2 id=\"see\">See</h2>\n\n<p>Maximum exit altitude AGL according to FAI Competition Rules Speed Skydiving\nsection 5.3.</p>\n", "default_value": "4268.29268292683"}, {"fullname": "ssscoring.constants.M_2_FT", "modulename": "ssscoring.constants", "qualname": "M_2_FT", "kind": "variable", "doc": "<p>Meters to feet conversion factor.</p>\n", "default_value": "3.28084"}, {"fullname": "ssscoring.constants.MIN_JUMP_FILE_SIZE", "modulename": "ssscoring.constants", "qualname": "MIN_JUMP_FILE_SIZE", "kind": "variable", "doc": "<p>FlySight v1 files smaller than <code>MIN_JUMP_FILE_SIZE</code> are ignored because they\nlack the minimum number of data points to contain a valid speed skydive.</p>\n", "default_value": "65536"}, {"fullname": "ssscoring.constants.MPS_2_KMH", "modulename": "ssscoring.constants", "qualname": "MPS_2_KMH", "kind": "variable", "doc": "<p>m/s to km/h conversion factor:</p>\n\n<div class=\"pdoc-code codehilite\">\n<pre><span></span><code><span class=\"n\">s</span> <span class=\"o\">=</span> <span class=\"n\">mps</span> <span class=\"o\">*</span> <span class=\"mi\">60</span> <span class=\"o\">*</span> <span class=\"mi\">60</span> <span class=\"o\">/</span> <span class=\"mi\">1000</span>\n  <span class=\"o\">=</span> <span class=\"n\">mps</span> <span class=\"o\">*</span> <span class=\"mi\">3600</span> <span class=\"o\">/</span> <span class=\"mi\">1000</span>\n  <span class=\"o\">=</span> <span class=\"n\">mps</span> <span class=\"o\">*</span> <span class=\"mf\">3.6</span>\n</code></pre>\n</div>\n", "default_value": "3.6"}, {"fullname": "ssscoring.constants.PERFORMANCE_WINDOW_LENGTH", "modulename": "ssscoring.constants", "qualname": "PERFORMANCE_WINDOW_LENGTH", "kind": "variable", "doc": "<p>Performance window length as defined by ISSA/IPC/USPA.</p>\n", "default_value": "2256.0"}, {"fullname": "ssscoring.constants.RESOURCES", "modulename": "ssscoring.constants", "qualname": "RESOURCES", "kind": "variable", "doc": "<p>The package resources in the manifest or package wheel resources.</p>\n", "default_value": "&#x27;ssscoring.resources&#x27;"}, {"fullname": "ssscoring.constants.SAMPLE_RATE", "modulename": "ssscoring.constants", "qualname": "SAMPLE_RATE", "kind": "variable", "doc": "<p>Expected interval, in seconds, for the FlySight sample rate.</p>\n", "default_value": "0.2"}, {"fullname": "ssscoring.constants.SCORING_INTERVAL", "modulename": "ssscoring.constants", "qualname": "SCORING_INTERVAL", "kind": "variable", "doc": "<p>Scoring is based on the maximum speed the jumper attained within the <code>VALIDATION_WINDOW_LENGTH</code>\nas the average speed during a sliding window of SCORING_INTERVAL seconds.  The\nvalue is set by governing bodies like ISC and USPA.</p>\n", "default_value": "3.0"}, {"fullname": "ssscoring.constants.SKYTRAX_1_HEADER", "modulename": "ssscoring.constants", "qualname": "SKYTRAX_1_HEADER", "kind": "variable", "doc": "<p>SkyTraX GPS + barometric SMD v1 CSV file headers.</p>\n", "default_value": "{&#x27;lon&#x27;, &#x27;velN&#x27;, &#x27;lat&#x27;, &#x27;gpsFix&#x27;, &#x27;hMSL&#x27;, &#x27;cAcc&#x27;, &#x27;hAcc&#x27;, &#x27;heading&#x27;, &#x27;velD&#x27;, &#x27;sAcc&#x27;, &#x27;numSV&#x27;, &#x27;time&#x27;, &#x27;velE&#x27;, &#x27;vAcc&#x27;}"}, {"fullname": "ssscoring.constants.SPEED_ACCURACY_THRESHOLD", "modulename": "ssscoring.constants", "qualname": "SPEED_ACCURACY_THRESHOLD", "kind": "variable", "doc": "<p>Speed accuracy for the FlySight device.</p>\n", "default_value": "3.0"}, {"fullname": "ssscoring.constants.SSSCORE_INSTRUCTIONS_MD", "modulename": "ssscoring.constants", "qualname": "SSSCORE_INSTRUCTIONS_MD", "kind": "variable", "doc": "<p>Markdown representation of the end-user instructions on how to use SSScore.</p>\n", "default_value": "&#x27;instructions.md&#x27;"}, {"fullname": "ssscoring.constants.SSSCORE_MOVED_DOMAIN_MD", "modulename": "ssscoring.constants", "qualname": "SSSCORE_MOVED_DOMAIN_MD", "kind": "variable", "doc": "<p>Markdown representation of the end-user instructions to go to the new SSScore\ndomain.</p>\n", "default_value": "&#x27;moved-2-new-domain.md&#x27;"}, {"fullname": "ssscoring.constants.TABLE_INTERVAL", "modulename": "ssscoring.constants", "qualname": "TABLE_INTERVAL", "kind": "variable", "doc": "<p>Speed run table interval.</p>\n", "default_value": "5.0"}, {"fullname": "ssscoring.constants.VALIDATION_WINDOW_LENGTH", "modulename": "ssscoring.constants", "qualname": "VALIDATION_WINDOW_LENGTH", "kind": "variable", "doc": "<p>The validation window length as defined in the competition rules.</p>\n", "default_value": "1006.0"}, {"fullname": "ssscoring.datatypes", "modulename": "ssscoring.datatypes", "kind": "module", "doc": "<p>SSScoring custom type definitions for easier symbolic manipuation.</p>\n"}, {"fullname": "ssscoring.datatypes.FlySightVersion", "modulename": "ssscoring.datatypes", "qualname": "FlySightVersion", "kind": "class", "doc": "<p>Symbols for handling device version.</p>\n", "bases": "enum.Enum"}, {"fullname": "ssscoring.datatypes.FlySightVersion.V1", "modulename": "ssscoring.datatypes", "qualname": "FlySightVersion.V1", "kind": "variable", "doc": "<p></p>\n", "default_value": "&lt;FlySightVersion.V1: 1000&gt;"}, {"fullname": "ssscoring.datatypes.FlySightVersion.V2", "modulename": "ssscoring.datatypes", "qualname": "FlySightVersion.V2", "kind": "variable", "doc": "<p></p>\n", "default_value": "&lt;FlySightVersion.V2: 2000&gt;"}, {"fullname": "ssscoring.datatypes.JumpStatus", "modulename": "ssscoring.datatypes", "qualname": "JumpStatus", "kind": "class", "doc": "<p></p>\n", "bases": "enum.Enum"}, {"fullname": "ssscoring.datatypes.JumpStatus.OK", "modulename": "ssscoring.datatypes", "qualname": "JumpStatus.OK", "kind": "variable", "doc": "<p></p>\n", "default_value": "&lt;JumpStatus.OK: 0&gt;"}, {"fullname": "ssscoring.datatypes.JumpStatus.ALTITUDE_EXCEEDS_MINIMUM", "modulename": "ssscoring.datatypes", "qualname": "JumpStatus.ALTITUDE_EXCEEDS_MINIMUM", "kind": "variable", "doc": "<p></p>\n", "default_value": "&lt;JumpStatus.ALTITUDE_EXCEEDS_MINIMUM: 100&gt;"}, {"fullname": "ssscoring.datatypes.JumpStatus.ALTITUDE_EXCEEDS_MAXIMUM", "modulename": "ssscoring.datatypes", "qualname": "JumpStatus.ALTITUDE_EXCEEDS_MAXIMUM", "kind": "variable", "doc": "<p></p>\n", "default_value": "&lt;JumpStatus.ALTITUDE_EXCEEDS_MAXIMUM: 110&gt;"}, {"fullname": "ssscoring.datatypes.JumpStatus.INVALID_SPEED_FILE", "modulename": "ssscoring.datatypes", "qualname": "JumpStatus.INVALID_SPEED_FILE", "kind": "variable", "doc": "<p></p>\n", "default_value": "&lt;JumpStatus.INVALID_SPEED_FILE: 120&gt;"}, {"fullname": "ssscoring.datatypes.JumpStatus.SPEED_ACCURACY_EXCEEDS_LIMIT", "modulename": "ssscoring.datatypes", "qualname": "JumpStatus.SPEED_ACCURACY_EXCEEDS_LIMIT", "kind": "variable", "doc": "<p></p>\n", "default_value": "&lt;JumpStatus.SPEED_ACCURACY_EXCEEDS_LIMIT: 200&gt;"}, {"fullname": "ssscoring.datatypes.JumpStatus.WARM_UP_FILE", "modulename": "ssscoring.datatypes", "qualname": "JumpStatus.WARM_UP_FILE", "kind": "variable", "doc": "<p></p>\n", "default_value": "&lt;JumpStatus.WARM_UP_FILE: 300&gt;"}, {"fullname": "ssscoring.datatypes.JumpResults", "modulename": "ssscoring.datatypes", "qualname": "JumpResults", "kind": "class", "doc": "<p>A named tuple containing the score, maximum speed, scores throught the\nperformance window, the results table for a jump, the output color for the\nresult, and the result information string.</p>\n\n<h2 id=\"attributes\">Attributes</h2>\n\n<ul>\n<li><code>data</code> - dataframe containing all the data points for plotting and\ncalculations</li>\n<li><code>maxSpeed</code> - maximum absolute speed registered during a skydive</li>\n<li><code>score</code> - maximum mean speed during a 3-second window during the skydive</li>\n<li><code>scores</code> - a dictionary with all the scored ruding the sliding 3-sec window\nfor the speed run</li>\n<li><code>table</code> - summary table of results of the speed run</li>\n<li><code>window</code> - the scoring window data, an instance of <code>PerformanceWindow</code></li>\n<li>'status' - An instance of <code>ssscoring.datatypes.JumpStatus</code></li>\n</ul>\n", "bases": "builtins.tuple"}, {"fullname": "ssscoring.datatypes.JumpResults.__init__", "modulename": "ssscoring.datatypes", "qualname": "JumpResults.__init__", "kind": "function", "doc": "<p>Create new instance of JumpResults(data, maxSpeed, score, scores, table, window, status)</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">data</span>, </span><span class=\"param\"><span class=\"n\">maxSpeed</span>, </span><span class=\"param\"><span class=\"n\">score</span>, </span><span class=\"param\"><span class=\"n\">scores</span>, </span><span class=\"param\"><span class=\"n\">table</span>, </span><span class=\"param\"><span class=\"n\">window</span>, </span><span class=\"param\"><span class=\"n\">status</span></span>)</span>"}, {"fullname": "ssscoring.datatypes.JumpResults.data", "modulename": "ssscoring.datatypes", "qualname": "JumpResults.data", "kind": "variable", "doc": "<p>Alias for field number 0</p>\n"}, {"fullname": "ssscoring.datatypes.JumpResults.maxSpeed", "modulename": "ssscoring.datatypes", "qualname": "JumpResults.maxSpeed", "kind": "variable", "doc": "<p>Alias for field number 1</p>\n"}, {"fullname": "ssscoring.datatypes.JumpResults.score", "modulename": "ssscoring.datatypes", "qualname": "JumpResults.score", "kind": "variable", "doc": "<p>Alias for field number 2</p>\n"}, {"fullname": "ssscoring.datatypes.JumpResults.scores", "modulename": "ssscoring.datatypes", "qualname": "JumpResults.scores", "kind": "variable", "doc": "<p>Alias for field number 3</p>\n"}, {"fullname": "ssscoring.datatypes.JumpResults.table", "modulename": "ssscoring.datatypes", "qualname": "JumpResults.table", "kind": "variable", "doc": "<p>Alias for field number 4</p>\n"}, {"fullname": "ssscoring.datatypes.JumpResults.window", "modulename": "ssscoring.datatypes", "qualname": "JumpResults.window", "kind": "variable", "doc": "<p>Alias for field number 5</p>\n"}, {"fullname": "ssscoring.datatypes.JumpResults.status", "modulename": "ssscoring.datatypes", "qualname": "JumpResults.status", "kind": "variable", "doc": "<p>Alias for field number 6</p>\n"}, {"fullname": "ssscoring.datatypes.PerformanceWindow", "modulename": "ssscoring.datatypes", "qualname": "PerformanceWindow", "kind": "class", "doc": "<p>An object to handle the performance window (as defined in competition rules) as\na single object with all the properties necessary to interpret it and manipulate\nit across different function or method calls.</p>\n\n<h2 id=\"attributes\">Attributes</h2>\n\n<ul>\n<li><code>start</code> - beginning or start of the performance window, or exit from the\naircraft</li>\n<li><code>end</code> - end of the performance window, or <code>start-PERFORMANCE_WINDOW_LENGTH</code></li>\n<li><code>validationStart</code> - end of the performance window - the <code>VALIDATION_WINDOW_END</code></li>\n</ul>\n\n<h2 id=\"see\">See</h2>\n\n<pre><code>ssscoring.constants.PERFORMANCE_WINDOW_LENGTH\nssscoring.constants.VALIDATION_WINDOW_END\n</code></pre>\n", "bases": "builtins.tuple"}, {"fullname": "ssscoring.datatypes.PerformanceWindow.__init__", "modulename": "ssscoring.datatypes", "qualname": "PerformanceWindow.__init__", "kind": "function", "doc": "<p>Create new instance of PerformanceWindow(start, end, validationStart)</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">start</span>, </span><span class=\"param\"><span class=\"n\">end</span>, </span><span class=\"param\"><span class=\"n\">validationStart</span></span>)</span>"}, {"fullname": "ssscoring.datatypes.PerformanceWindow.start", "modulename": "ssscoring.datatypes", "qualname": "PerformanceWindow.start", "kind": "variable", "doc": "<p>Alias for field number 0</p>\n"}, {"fullname": "ssscoring.datatypes.PerformanceWindow.end", "modulename": "ssscoring.datatypes", "qualname": "PerformanceWindow.end", "kind": "variable", "doc": "<p>Alias for field number 1</p>\n"}, {"fullname": "ssscoring.datatypes.PerformanceWindow.validationStart", "modulename": "ssscoring.datatypes", "qualname": "PerformanceWindow.validationStart", "kind": "variable", "doc": "<p>Alias for field number 2</p>\n"}, {"fullname": "ssscoring.errors", "modulename": "ssscoring.errors", "kind": "module", "doc": "<p></p>\n"}, {"fullname": "ssscoring.errors.SSScoringError", "modulename": "ssscoring.errors", "qualname": "SSScoringError", "kind": "class", "doc": "<p>Abstract class that defines all exceptions and errors and has a dictionary\nrepresentation of itself, for cleaner structured logging.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>message : str\n</code></pre>\n\n<p>A meaningful error message, human-readable\n    errno : int\nAn optional integer value, similar to ERRNO in C/UNIX</p>\n", "bases": "builtins.Exception"}, {"fullname": "ssscoring.errors.SSScoringError.__init__", "modulename": "ssscoring.errors", "qualname": "SSScoringError.__init__", "kind": "function", "doc": "<p></p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">message</span><span class=\"p\">:</span> <span class=\"nb\">str</span>, </span><span class=\"param\"><span class=\"n\">errno</span><span class=\"p\">:</span> <span class=\"nb\">int</span> <span class=\"o\">=</span> <span class=\"o\">-</span><span class=\"mi\">1</span></span>)</span>"}, {"fullname": "ssscoring.flysight", "modulename": "ssscoring.flysight", "kind": "module", "doc": "<p>Functions and logic for detecting, validating and manipulating\nFlySight CSV files, including detection in the file system.  The functions in\nthis module assume that a data lake exists somewhere in the file system (whether\nlocal or cloud-based).</p>\n"}, {"fullname": "ssscoring.flysight.isCRMangledCSV", "modulename": "ssscoring.flysight", "qualname": "isCRMangledCSV", "kind": "function", "doc": "<p>Tests if <code>fileThing</code> is an Excel or Dropbox DOS file with lines terminated\nin CRCRLF.  These occur when someone opens the file with Excel or some other\ntool in a Windows system and saves the file back to the file system,\nmangling the original format.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>fileThing\n</code></pre>\n\n<p>A string or <code>pathlib.Path</code> object associated with what looks like a FlySight\nCR mangled file.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p><code>True</code> if the file has one or more lines ending in CRCRLF within the first\n512 bytes of data.</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">fileThing</span></span><span class=\"return-annotation\">) -> <span class=\"nb\">bool</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.flysight.fixCRMangledCSV", "modulename": "ssscoring.flysight", "qualname": "fixCRMangledCSV", "kind": "function", "doc": "<p>Open the file associated with <code>fileThing</code> and repleace all`</p>\n\n<p>\b<code>with\n</code>\n` EOL markers.</p>\n\n<pre><code>Arguments\n---------\n    fileThing\nA string or `pathlib.Path` object associated with what looks like a FlySight\nCR mangled file.\n\nSee\n---\n`ssscoring.flysight.isCRMangledCSV`\n</code></pre>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">fileThing</span></span><span class=\"return-annotation\">):</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.flysight.skipOverFS2MetadataRowsIn", "modulename": "ssscoring.flysight", "qualname": "skipOverFS2MetadataRowsIn", "kind": "function", "doc": "<p>Returns a clean dataframe on which any metadata rows within the first 100\nare skipped.  This function uses the <code>time</code> column to detect valid rows.  A\n<code>time == NaN</code> is considered invalid and skipped.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>data\n</code></pre>\n\n<p>A FlySight 2 dataframe suspected of having dirty N first rows with metadata</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p>A FlySight 2 clean dataframe without any leading metadata rows.</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">data</span><span class=\"p\">:</span> <span class=\"n\">pandas</span><span class=\"o\">.</span><span class=\"n\">core</span><span class=\"o\">.</span><span class=\"n\">frame</span><span class=\"o\">.</span><span class=\"n\">DataFrame</span></span><span class=\"return-annotation\">) -> <span class=\"n\">pandas</span><span class=\"o\">.</span><span class=\"n\">core</span><span class=\"o\">.</span><span class=\"n\">frame</span><span class=\"o\">.</span><span class=\"n\">DataFrame</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.flysight.validFlySightHeaderIn", "modulename": "ssscoring.flysight", "qualname": "validFlySightHeaderIn", "kind": "function", "doc": "<p>Checks if a file is a CSV in FlySight 1 or FlySight 2 formats.  The checks\ninclude:</p>\n\n<ul>\n<li>Whether the file is a CSV, using a comma delimiter</li>\n<li>Checks for the presence of all the documented FlySight 1 headers</li>\n<li>Checks for the presence of the FlySight 2 line 1 identifier</li>\n</ul>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>fileThingCSV\n</code></pre>\n\n<p>A file thing to verify as a valid FlySight file; can be a string, an\ninstance of <code>libpath.Path</code>, or a buffer of <code>bytes</code>.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p><code>True</code> if <code>fileThingCSV</code> is a FlySight CSV file, otherwise <code>False</code>.</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">fileThingCSV</span></span><span class=\"return-annotation\">) -> <span class=\"nb\">bool</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.flysight.getAllSpeedJumpFilesFrom", "modulename": "ssscoring.flysight", "qualname": "getAllSpeedJumpFilesFrom", "kind": "function", "doc": "<p>Get a list of all the speed jump files from a data lake, where data lake is\ndefined as a reachable path that contains one or more FlySight CSV files.\nThis function tests each file to ensure that it's a speed skydive FlySight\nfile in a valid format and length.  It doesn't validate data like versions\nprior to 1.9.0.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>dataLake: str\n</code></pre>\n\n<p>A valid (absolute or relative) path name to the top level directory where\nthe data lake starts.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p>A dictionary of speed jump file names for later SSScoring processing:\n    - keys are the file names\n    - values are a FlySight version string tag</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">dataLake</span><span class=\"p\">:</span> <span class=\"n\">pathlib</span><span class=\"o\">.</span><span class=\"n\">Path</span></span><span class=\"return-annotation\">) -> <span class=\"nb\">dict</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.flysight.detectFlySightFileVersionOf", "modulename": "ssscoring.flysight", "qualname": "detectFlySightFileVersionOf", "kind": "function", "doc": "<p>Detects the FlySight file version based on its file name and format.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>fileThing\n</code></pre>\n\n<p>A string, <code>bytes</code> buffer or <code>pathlib.Path</code> object corresponding to track\nfile.  If string or <code>pathlib.Path</code>, it'll be treated as a file.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p>An instance of <code>ssscoring.flysight.FlySightVersion</code> with a valid version\nsymbolic value.</p>\n\n<h2 id=\"errors\">Errors</h2>\n\n<p><code>ssscoring.errors.SSScoringError</code> if the file is not a CSV and it's some\nother invalid format.</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">fileThing</span></span><span class=\"return-annotation\">) -> <span class=\"n\">ssscoring</span><span class=\"o\">.</span><span class=\"n\">datatypes</span><span class=\"o\">.</span><span class=\"n\">FlySightVersion</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.mapview", "modulename": "ssscoring.mapview", "kind": "module", "doc": "<p></p>\n"}, {"fullname": "ssscoring.mapview.DISTANCE_FROM_MIDDLE", "modulename": "ssscoring.mapview", "qualname": "DISTANCE_FROM_MIDDLE", "kind": "variable", "doc": "<p>The distance in meters from the middle of the skydive to the outer bounding box\nfor the initial view of a new rendered map.</p>\n", "default_value": "400.0"}, {"fullname": "ssscoring.mapview.viewPointBox", "modulename": "ssscoring.mapview", "qualname": "viewPointBox", "kind": "function", "doc": "<p>Calculate the NW and SE corners of a \"box\" delimiting the viewport area\n<code>DISTANCE_FROM_MIDDLE</code> meters away from the middle of the speed skydive.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>data\n</code></pre>\n\n<p>A SSScoring dataframe with jump data.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p>The NW and SE corners of the box, as terrestrial coordinates, in a dataframe\nwith these columns:</p>\n\n<ul>\n<li><code>latitude</code></li>\n<li><code>lontigude</code></li>\n</ul>\n\n<h2 id=\"see\">See</h2>\n\n<p><code>ssscoring.calc.convertFlySight2SSScoring</code></p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">data</span><span class=\"p\">:</span> <span class=\"n\">pandas</span><span class=\"o\">.</span><span class=\"n\">core</span><span class=\"o\">.</span><span class=\"n\">frame</span><span class=\"o\">.</span><span class=\"n\">DataFrame</span></span><span class=\"return-annotation\">) -> <span class=\"n\">pandas</span><span class=\"o\">.</span><span class=\"n\">core</span><span class=\"o\">.</span><span class=\"n\">frame</span><span class=\"o\">.</span><span class=\"n\">DataFrame</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.mapview.speedJumpTrajectory", "modulename": "ssscoring.mapview", "qualname": "speedJumpTrajectory", "kind": "function", "doc": "<p>Build the layers for a PyDeck map showing a jumper's trajectory.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>jumpResult\n</code></pre>\n\n<p>A SSScoring <code>JumpResults</code> instance with the results of the jump.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p>A PyDeck <code>deck</code> instance ready for rendering using PyDeck or Streamlit\nmapping facilities.</p>\n\n<h2 id=\"see\">See</h2>\n\n<p><code>st.pydeck_chart</code>\n<code>st.map</code></p>\n", "signature": "<span class=\"signature pdoc-code multiline\">(<span class=\"param\">\t<span class=\"n\">jumpResult</span><span class=\"p\">:</span> <span class=\"n\">ssscoring</span><span class=\"o\">.</span><span class=\"n\">datatypes</span><span class=\"o\">.</span><span class=\"n\">JumpResults</span>,</span><span class=\"param\">\t<span class=\"n\">displayScorePoint</span><span class=\"p\">:</span> <span class=\"nb\">bool</span> <span class=\"o\">=</span> <span class=\"kc\">True</span></span><span class=\"return-annotation\">) -> <span class=\"n\">pydeck</span><span class=\"o\">.</span><span class=\"n\">bindings</span><span class=\"o\">.</span><span class=\"n\">deck</span><span class=\"o\">.</span><span class=\"n\">Deck</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.mapview.multipleSpeedJumpsTrajectories", "modulename": "ssscoring.mapview", "qualname": "multipleSpeedJumpsTrajectories", "kind": "function", "doc": "<p>Build all the layers for a PyDeck map showing the trajectories of every jump\nin the results set.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>jumpResults\n</code></pre>\n\n<p>A dictionary of all the jump results after processing.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p>A PyDeck <code>deck</code> instance ready for rendering using PyDeck or Streamlit\nmapping facilities.</p>\n\n<h2 id=\"see\">See</h2>\n\n<p><code>st.pydeck_chart</code>\n<code>st.map</code></p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">jumpResults</span></span><span class=\"return-annotation\">):</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.notebook", "modulename": "ssscoring.notebook", "kind": "module", "doc": "<h2 id=\"utility-reusable-code-for-notebooks\">Utility reusable code for notebooks.</h2>\n"}, {"fullname": "ssscoring.notebook.DEFAULT_AXIS_COLOR_BOKEH", "modulename": "ssscoring.notebook", "qualname": "DEFAULT_AXIS_COLOR_BOKEH", "kind": "variable", "doc": "<p>CSS color name for the axis colors used in notebooks and Streamlit\nwith Bokeh.</p>\n", "default_value": "&#x27;lightsteelblue&#x27;"}, {"fullname": "ssscoring.notebook.initializePlot", "modulename": "ssscoring.notebook", "qualname": "initializePlot", "kind": "function", "doc": "<p>Initiialize a plotting area for notebook output.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>jumpTitle: str\n</code></pre>\n\n<p>A title to identify the plot.</p>\n\n<pre><code>height: int\n</code></pre>\n\n<p>Height of the plot in pixels.  Default = 500.</p>\n\n<pre><code>width: int\n</code></pre>\n\n<p>Width of the plot in pixels.  Default = 900.</p>\n\n<pre><code>xLabel: str\n</code></pre>\n\n<p>X axis label.  Default:  <code>'seconds from exit'</code></p>\n\n<pre><code>yLabel: str\n</code></pre>\n\n<p>Y axis label.  Default:  <code>'km/h'</code></p>\n\n<pre><code>xMax: float\n</code></pre>\n\n<p>The maximum rnage for the X axis.  Default = 40.0</p>\n\n<pre><code>yMax: float\n</code></pre>\n\n<p>The maximum range for the Y axis.  Default = <code>DEFAULT_PLOT_MAX_V_SCALE</code></p>\n\n<pre><code>backgroundColorName\n</code></pre>\n\n<p>A string with the CSS RGB value of the background color or its CSS color\nstring name.</p>\n\n<pre><code>colorName\n</code></pre>\n\n<p>A valid CSS color string.</p>\n", "signature": "<span class=\"signature pdoc-code multiline\">(<span class=\"param\">\t<span class=\"n\">jumpTitle</span><span class=\"p\">:</span> <span class=\"nb\">str</span>,</span><span class=\"param\">\t<span class=\"n\">height</span><span class=\"o\">=</span><span class=\"mi\">500</span>,</span><span class=\"param\">\t<span class=\"n\">width</span><span class=\"o\">=</span><span class=\"mi\">900</span>,</span><span class=\"param\">\t<span class=\"n\">xLabel</span><span class=\"o\">=</span><span class=\"s1\">&#39;seconds from exit&#39;</span>,</span><span class=\"param\">\t<span class=\"n\">yLabel</span><span class=\"o\">=</span><span class=\"s1\">&#39;km/h&#39;</span>,</span><span class=\"param\">\t<span class=\"n\">xMax</span><span class=\"o\">=</span><span class=\"mf\">35.0</span>,</span><span class=\"param\">\t<span class=\"n\">yMax</span><span class=\"o\">=</span><span class=\"mf\">550.0</span>,</span><span class=\"param\">\t<span class=\"n\">backgroundColorName</span><span class=\"o\">=</span><span class=\"s1\">&#39;#1a1a1a&#39;</span>,</span><span class=\"param\">\t<span class=\"n\">colorName</span><span class=\"o\">=</span><span class=\"s1\">&#39;lightsteelblue&#39;</span></span><span class=\"return-annotation\">):</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.notebook.initializeExtraYRanges", "modulename": "ssscoring.notebook", "qualname": "initializeExtraYRanges", "kind": "function", "doc": "<p>Initialize an extra Y range for reporting other data trend (e.g. altitude)\nin the plot.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>plot\n</code></pre>\n\n<p>A valid instance of <code>bp.figure</code> with an existing plot defined for it</p>\n\n<pre><code>startY: float\n</code></pre>\n\n<p>The Y range starting value</p>\n\n<pre><code>endY: float\n</code></pre>\n\n<p>The Y range ending value</p>\n\n<pre><code>maxSpeedAccuracy: float\n</code></pre>\n\n<p>Maximum speed accuracy value to determine the range of the speed accuracy axis.\nIf None or &lt; SPEED_ACCURACY_THRESHOLD, range is 0-10. Otherwise, range is 0-maxSpeedAccuracy*1.1</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p>An instance of <code>bp.figure</code> updated to report an additional Y axis.</p>\n", "signature": "<span class=\"signature pdoc-code multiline\">(<span class=\"param\">\t<span class=\"n\">plot</span>,</span><span class=\"param\">\t<span class=\"n\">startY</span><span class=\"p\">:</span> <span class=\"nb\">float</span> <span class=\"o\">=</span> <span class=\"mf\">0.0</span>,</span><span class=\"param\">\t<span class=\"n\">endY</span><span class=\"p\">:</span> <span class=\"nb\">float</span> <span class=\"o\">=</span> <span class=\"mf\">14000.0</span>,</span><span class=\"param\">\t<span class=\"n\">maxSpeedAccuracy</span><span class=\"p\">:</span> <span class=\"nb\">float</span> <span class=\"o\">|</span> <span class=\"kc\">None</span> <span class=\"o\">=</span> <span class=\"kc\">None</span></span><span class=\"return-annotation\">):</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.notebook.validationWindowDataFrom", "modulename": "ssscoring.notebook", "qualname": "validationWindowDataFrom", "kind": "function", "doc": "<p>Generate the validation window dataset for plotting the ISC speed accuracy\nvalues.  It's a subset defined from the end of the scoring window to the\nvalidation start.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>data\n</code></pre>\n\n<p>A dataframe with the <code>plotTime</code> column set, with all the jump data, after\nspeed validation processing.</p>\n\n<pre><code>window\n</code></pre>\n\n<p>A <code>ssscoring.datatypes.PerformanceWindow</code> instance, with the <code>validationStart</code>\nvalue initialized.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p>A column data source ready for plotting the Y-values of a Bokeh chart.</p>\n", "signature": "<span class=\"signature pdoc-code multiline\">(<span class=\"param\">\t<span class=\"n\">data</span><span class=\"p\">:</span> <span class=\"n\">pandas</span><span class=\"o\">.</span><span class=\"n\">core</span><span class=\"o\">.</span><span class=\"n\">frame</span><span class=\"o\">.</span><span class=\"n\">DataFrame</span>,</span><span class=\"param\">\t<span class=\"n\">window</span><span class=\"p\">:</span> <span class=\"n\">ssscoring</span><span class=\"o\">.</span><span class=\"n\">datatypes</span><span class=\"o\">.</span><span class=\"n\">PerformanceWindow</span></span><span class=\"return-annotation\">) -> <span class=\"n\">bokeh</span><span class=\"o\">.</span><span class=\"n\">models</span><span class=\"o\">.</span><span class=\"n\">sources</span><span class=\"o\">.</span><span class=\"n\">ColumnDataSource</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.notebook.graphJumpResult", "modulename": "ssscoring.notebook", "qualname": "graphJumpResult", "kind": "function", "doc": "<p>Graph the jump results using the initialized plot.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>plot: bp.figure\n</code></pre>\n\n<p>A Bokeh figure where to render the plot.</p>\n\n<pre><code>jumpResult: ssscoring.JumpResults\n</code></pre>\n\n<p>A jump results named tuple with score, max speed, scores, data, etc.</p>\n\n<pre><code>lineColor: str\n</code></pre>\n\n<p>A valid color from the Bokeh palette:  <a href=\"https://docs.bokeh.org/en/2.1.1/docs/reference/colors.html\">https://docs.bokeh.org/en/2.1.1/docs/reference/colors.html</a>\nThis module defines 8 colors for rendering a competition's results.  See:\n<code>ssscoring.notebook.SPEED_COLORS</code> for the list.</p>\n\n<pre><code>legend: str\n</code></pre>\n\n<p>A title for the plot.</p>\n\n<pre><code>showIt: bool\n</code></pre>\n\n<p>A boolean flag for whether the call should render the max speed, time,\nhorizontal speed, etc. in the current plot.  This is used for discriminating\nbetween single jump plots and plotting only the speed for the aggregate\nplot display for a competition or training session.</p>\n\n<p>To display the actual plot, use <code>bp.show(plot)</code> if running from Lucyfer/Jupyter\nor use <code>st.bokeh_chart(plot)</code> if in the Streamlit environment.</p>\n\n<div class=\"pdoc-code codehilite\">\n<pre><span></span><code><span class=\"c1\"># Basic usage showing speed accuracy overlay</span>\n<span class=\"n\">graphJumpResult</span><span class=\"p\">(</span><span class=\"n\">plot</span><span class=\"p\">,</span> <span class=\"n\">result</span><span class=\"p\">)</span>\n<span class=\"n\">bp</span><span class=\"o\">.</span><span class=\"n\">show</span><span class=\"p\">(</span><span class=\"n\">plot</span><span class=\"p\">)</span>\n\n<span class=\"c1\"># Multiple jumps without speed accuracy overlay</span>\n<span class=\"k\">for</span> <span class=\"n\">result</span> <span class=\"ow\">in</span> <span class=\"n\">jumpResults</span><span class=\"p\">:</span>\n    <span class=\"n\">graphJumpResult</span><span class=\"p\">(</span><span class=\"n\">plot</span><span class=\"p\">,</span> <span class=\"n\">result</span><span class=\"p\">,</span> <span class=\"n\">showIt</span><span class=\"o\">=</span><span class=\"kc\">False</span><span class=\"p\">,</span> <span class=\"n\">showAccuracy</span><span class=\"o\">=</span><span class=\"kc\">False</span><span class=\"p\">)</span>\n<span class=\"n\">bp</span><span class=\"o\">.</span><span class=\"n\">show</span><span class=\"p\">(</span><span class=\"n\">plot</span><span class=\"p\">)</span>\n</code></pre>\n</div>\n\n<p>Another alternative use is in Streamlit.io applications:</p>\n\n<div class=\"pdoc-code codehilite\">\n<pre><span></span><code><span class=\"c1\"># Streamlit app with speed accuracy overlay</span>\n<span class=\"n\">graphJumpResult</span><span class=\"p\">(</span><span class=\"n\">plot</span><span class=\"p\">,</span> <span class=\"n\">result</span><span class=\"p\">,</span> <span class=\"n\">showIt</span><span class=\"o\">=</span><span class=\"kc\">False</span><span class=\"p\">)</span>\n<span class=\"n\">st</span><span class=\"o\">.</span><span class=\"n\">bokeh_chart</span><span class=\"p\">(</span><span class=\"n\">plot</span><span class=\"p\">,</span> <span class=\"n\">use_container_width</span><span class=\"o\">=</span><span class=\"kc\">True</span><span class=\"p\">)</span>\n</code></pre>\n</div>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p><code>None</code>.</p>\n", "signature": "<span class=\"signature pdoc-code multiline\">(<span class=\"param\">\t<span class=\"n\">plot</span>,</span><span class=\"param\">\t<span class=\"n\">jumpResult</span>,</span><span class=\"param\">\t<span class=\"n\">lineColor</span><span class=\"o\">=</span><span class=\"s1\">&#39;green&#39;</span>,</span><span class=\"param\">\t<span class=\"n\">legend</span><span class=\"o\">=</span><span class=\"s1\">&#39;speed&#39;</span>,</span><span class=\"param\">\t<span class=\"n\">showIt</span><span class=\"o\">=</span><span class=\"kc\">True</span>,</span><span class=\"param\">\t<span class=\"n\">showAccuracy</span><span class=\"o\">=</span><span class=\"kc\">True</span></span><span class=\"return-annotation\">):</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.notebook.graphAltitude", "modulename": "ssscoring.notebook", "qualname": "graphAltitude", "kind": "function", "doc": "<p>Graph a vertical axis with additional data, often used for altitude in ft\nASL.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>plot: pb.figure\n</code></pre>\n\n<p>A Bokeh figure where to render the plot.</p>\n\n<pre><code>jumpResult: ssscoring.JumpResults\n</code></pre>\n\n<p>A jump results named tuple with score, max speed, scores, data, etc.</p>\n\n<pre><code>label: str\n</code></pre>\n\n<p>The legend label for the new Y axis.</p>\n\n<pre><code>lineColor: str\n</code></pre>\n\n<p>A color name from the Bokeh palette.</p>\n\n<pre><code>rangeName: str\n</code></pre>\n\n<p>The range name to associate the <code>LinearAxis</code> layout with the data for\nplotting.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p><code>None</code>.</p>\n", "signature": "<span class=\"signature pdoc-code multiline\">(<span class=\"param\">\t<span class=\"n\">plot</span>,</span><span class=\"param\">\t<span class=\"n\">jumpResult</span>,</span><span class=\"param\">\t<span class=\"n\">label</span><span class=\"o\">=</span><span class=\"s1\">&#39;Alt (ft)&#39;</span>,</span><span class=\"param\">\t<span class=\"n\">lineColor</span><span class=\"o\">=</span><span class=\"s1\">&#39;palegoldenrod&#39;</span>,</span><span class=\"param\">\t<span class=\"n\">rangeName</span><span class=\"o\">=</span><span class=\"s1\">&#39;altitudeFt&#39;</span></span><span class=\"return-annotation\">):</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.notebook.graphAngle", "modulename": "ssscoring.notebook", "qualname": "graphAngle", "kind": "function", "doc": "<p>Graph the flight angle</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>plot: pb.figure\n</code></pre>\n\n<p>A Bokeh figure where to render the plot.</p>\n\n<pre><code>jumpResult: ssscoring.JumpResults\n</code></pre>\n\n<p>A jump results named tuple with score, max speed, scores, data, etc.</p>\n\n<pre><code>label: str\n</code></pre>\n\n<p>The legend label for the new Y axis.</p>\n\n<pre><code>lineColor: str\n</code></pre>\n\n<p>A color name from the Bokeh palette.</p>\n\n<pre><code>rangeName: str\n</code></pre>\n\n<p>The range name to associate the <code>LinearAxis</code> layout with the data for\nplotting.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p><code>None</code>.</p>\n", "signature": "<span class=\"signature pdoc-code multiline\">(<span class=\"param\">\t<span class=\"n\">plot</span>,</span><span class=\"param\">\t<span class=\"n\">jumpResult</span>,</span><span class=\"param\">\t<span class=\"n\">label</span><span class=\"o\">=</span><span class=\"s1\">&#39;angle&#39;</span>,</span><span class=\"param\">\t<span class=\"n\">lineColor</span><span class=\"o\">=</span><span class=\"s1\">&#39;deepskyblue&#39;</span>,</span><span class=\"param\">\t<span class=\"n\">rangeName</span><span class=\"o\">=</span><span class=\"s1\">&#39;angle&#39;</span></span><span class=\"return-annotation\">):</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.notebook.graphAcceleration", "modulename": "ssscoring.notebook", "qualname": "graphAcceleration", "kind": "function", "doc": "<p>Graph the flight acceleration curve.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>plot: pb.figure\n</code></pre>\n\n<p>A Bokeh figure where to render the plot.</p>\n\n<pre><code>jumpResult: ssscoring.JumpResults\n</code></pre>\n\n<p>A jump results named tuple with score, max speed, scores, data, etc.</p>\n\n<pre><code>label: str\n</code></pre>\n\n<p>The legend label for the new Y axis.</p>\n\n<pre><code>lineColor: str\n</code></pre>\n\n<p>A color name from the Bokeh palette.</p>\n\n<pre><code>rangeName: str\n</code></pre>\n\n<p>The range name to associate the <code>LinearAxis</code> layout with the data for\nplotting.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p><code>None</code>.</p>\n", "signature": "<span class=\"signature pdoc-code multiline\">(<span class=\"param\">\t<span class=\"n\">plot</span>,</span><span class=\"param\">\t<span class=\"n\">jumpResult</span>,</span><span class=\"param\">\t<span class=\"n\">label</span><span class=\"o\">=</span><span class=\"s1\">&#39;V-accel m/s\u00b2&#39;</span>,</span><span class=\"param\">\t<span class=\"n\">lineColor</span><span class=\"o\">=</span><span class=\"s1\">&#39;magenta&#39;</span>,</span><span class=\"param\">\t<span class=\"n\">rangeName</span><span class=\"o\">=</span><span class=\"s1\">&#39;vAccelMS2&#39;</span></span><span class=\"return-annotation\">):</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.notebook.convertHexColorToRGB", "modulename": "ssscoring.notebook", "qualname": "convertHexColorToRGB", "kind": "function", "doc": "<p>Converts a color in the format <code>#a0b1c2</code> to its RGB equivalent as a list\nof three values 0-255.</p>\n\n<h2 id=\"arguments\">Arguments</h2>\n\n<pre><code>color\n</code></pre>\n\n<p>A <code>str</code> in the form '#xxyyzz` where xx, yy, and zz are values in the hex\nrange 00-FF.  color is case insensitive.</p>\n\n<h2 id=\"returns\">Returns</h2>\n\n<p>A list of 3 integers, each in the range 0-255 corresponding to the hex\ncolor value.</p>\n\n<h2 id=\"raises\">Raises</h2>\n\n<p><code>SSScoringError' if</code>color` is an invalid hex-encoded textual RGB value.\nThe string value of the exception describes the error cause.</p>\n\n<p><code>ValueError</code> if the characters that make the hex value are not in the\nrange 0-9, a-f.</p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"param\"><span class=\"n\">color</span><span class=\"p\">:</span> <span class=\"nb\">str</span></span><span class=\"return-annotation\">) -> <span class=\"nb\">list</span>:</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.resources", "modulename": "ssscoring.resources", "kind": "module", "doc": "<p></p>\n"}, {"fullname": "ssscoring.ssscoremoved", "modulename": "ssscoring.ssscoremoved", "kind": "module", "doc": "<h2 id=\"experimental\">Experimental</h2>\n\n<p>Process a group of jumps uploaded from a file uploader.</p>\n"}, {"fullname": "ssscoring.ssscoremoved.main", "modulename": "ssscoring.ssscoremoved", "qualname": "main", "kind": "function", "doc": "<p></p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"return-annotation\">):</span></span>", "funcdef": "def"}, {"fullname": "ssscoring.ssscoremultiple", "modulename": "ssscoring.ssscoremultiple", "kind": "module", "doc": "<h2 id=\"experimental\">Experimental</h2>\n\n<p>Process a group of jumps uploaded from a file uploader.</p>\n"}, {"fullname": "ssscoring.ssscoremultiple.main", "modulename": "ssscoring.ssscoremultiple", "qualname": "main", "kind": "function", "doc": "<p></p>\n", "signature": "<span class=\"signature pdoc-code condensed\">(<span class=\"return-annotation\">):</span></span>", "funcdef": "def"}];

